import{_ as o,c as t,o as a,a1 as n}from"./chunks/framework.DDNAyvCW.js";const r="/assets/aichat.DzFmaWbj.png",m=JSON.parse('{"title":"AI Dialog","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/dialogs/index.md","filePath":"docs/ai/dialogs/index.md"}'),s={name:"docs/ai/dialogs/index.md"};function i(l,e,c,d,h,u){return a(),t("div",null,e[0]||(e[0]=[n('<h1 id="ai-dialog" tabindex="-1">AI Dialog <a class="header-anchor" href="#ai-dialog" aria-label="Permalink to &quot;AI Dialog&quot;">​</a></h1><blockquote><p>The AI dialog feature enables intelligent interaction with artificial intelligence, improving work efficiency.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The AI dialog sidebar is one of the core features of the Chaterm application, providing users with powerful AI dialog capabilities. It supports multiple dialog modes, intelligent command execution, file uploads, voice input, and other features, designed to enhance user terminal operation efficiency.</p><p><img src="'+r+'" alt=""></p><h2 id="main-features" tabindex="-1">Main Features <a class="header-anchor" href="#main-features" aria-label="Permalink to &quot;Main Features&quot;">​</a></h2><h3 id="_1-dialog-modes" tabindex="-1">1. Dialog Modes <a class="header-anchor" href="#_1-dialog-modes" aria-label="Permalink to &quot;1. Dialog Modes&quot;">​</a></h3><p>The AI sidebar supports two dialog modes:</p><h4 id="command-mode" tabindex="-1">Command Mode <a class="header-anchor" href="#command-mode" aria-label="Permalink to &quot;Command Mode&quot;">​</a></h4><blockquote><p><strong>Purpose</strong>: Generate and execute terminal commands<br><strong>Features</strong>: AI generates executable commands, users can choose to copy or execute directly<br><strong>Use Cases</strong>: System management, file operations, development tasks, etc.</p></blockquote><h4 id="agent-mode" tabindex="-1">Agent Mode <a class="header-anchor" href="#agent-mode" aria-label="Permalink to &quot;Agent Mode&quot;">​</a></h4><blockquote><p><strong>Purpose</strong>: Intelligent agent that can execute complex multi-step tasks<br><strong>Features</strong>: AI can autonomously execute commands and handle interactive commands<br><strong>Use Cases</strong>: Automated tasks, complex workflows, etc.</p></blockquote><h3 id="_2-message-system" tabindex="-1">2. Message System <a class="header-anchor" href="#_2-message-system" aria-label="Permalink to &quot;2. Message System&quot;">​</a></h3><h4 id="message-types" tabindex="-1">Message Types <a class="header-anchor" href="#message-types" aria-label="Permalink to &quot;Message Types&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>User Message</strong></td><td>User input content</td></tr><tr><td><strong>Assistant Message</strong></td><td>AI response</td></tr><tr><td><strong>Command Message</strong></td><td>Generated command code</td></tr><tr><td><strong>Output Message</strong></td><td>Command execution results</td></tr><tr><td><strong>Thinking Message</strong></td><td>AI reasoning process (Thinking mode)</td></tr></tbody></table><h3 id="_3-intelligent-features" tabindex="-1">3. Intelligent Features <a class="header-anchor" href="#_3-intelligent-features" aria-label="Permalink to &quot;3. Intelligent Features&quot;">​</a></h3><h4 id="image-upload" tabindex="-1">Image Upload <a class="header-anchor" href="#image-upload" aria-label="Permalink to &quot;Image Upload&quot;">​</a></h4><blockquote><p><strong>Supported Formats</strong>: <code>.png</code>, <code>.jpg</code>, <code>.jpeg</code>, <code>.webp</code><br><strong>Maximum File Size</strong>: 5MB<br><strong>How to Use</strong>: Drag and drop images into the input box or select them via the upload button</p></blockquote><h4 id="file-upload" tabindex="-1">File Upload <a class="header-anchor" href="#file-upload" aria-label="Permalink to &quot;File Upload&quot;">​</a></h4><blockquote><p><strong>Supported Formats</strong>: <code>.txt</code>, <code>.md</code>, <code>.js</code>, <code>.ts</code>, <code>.py</code>, <code>.java</code>, <code>.cpp</code>, <code>.c</code>, <code>.html</code>, <code>.css</code>, <code>.json</code>, <code>.xml</code>, <code>.yaml</code>, <code>.yml</code>, <code>.sql</code>, <code>.sh</code>, <code>.bat</code>, <code>.ps1</code>, <code>.log</code>, <code>.csv</code>, <code>.tsv</code><br><strong>Maximum File Size</strong>: 1MB<br><strong>Smart Formatting</strong>: Automatically adds code block markers based on file type</p></blockquote><h4 id="host-management" tabindex="-1">Host Management <a class="header-anchor" href="#host-management" aria-label="Permalink to &quot;Host Management&quot;">​</a></h4><blockquote><p><strong>Auto Detection</strong>: Automatically detects the host connected to the current terminal<br><strong>Manual Selection</strong>: Agent mode supports manual @ selection of target hosts<br><strong>Multi-Host Support</strong>: Agent mode supports multi-host operations<br><strong>Connection Types</strong>: Supports personal connections and JumpServer connections</p></blockquote><h3 id="_4-history-management" tabindex="-1">4. History Management <a class="header-anchor" href="#_4-history-management" aria-label="Permalink to &quot;4. History Management&quot;">​</a></h3><h4 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h4><blockquote><p><strong>Auto Save</strong>: All conversations are automatically saved locally<br><strong>Search Function</strong>: Supports searching history by title<br><strong>Favorite Function</strong>: Can favorite important conversations<br><strong>Pagination</strong>: Supports paginated display of large amounts of history<br><strong>Edit Title</strong>: Can customize conversation titles</p></blockquote><h4 id="history-operations" tabindex="-1">History Operations <a class="header-anchor" href="#history-operations" aria-label="Permalink to &quot;History Operations&quot;">​</a></h4><blockquote><p><strong>Restore Conversation</strong>: Click on history to restore previous conversations<br><strong>Delete Record</strong>: Supports deleting unwanted history records<br><strong>Favorite Management</strong>: Can add or remove favorite markers</p></blockquote><h3 id="_5-interactive-features" tabindex="-1">5. Interactive Features <a class="header-anchor" href="#_5-interactive-features" aria-label="Permalink to &quot;5. Interactive Features&quot;">​</a></h3><h4 id="command-operations" tabindex="-1">Command Operations <a class="header-anchor" href="#command-operations" aria-label="Permalink to &quot;Command Operations&quot;">​</a></h4><blockquote><p><strong>Approve Execution</strong>: Users can choose to approve AI-generated commands<br><strong>Reject Operation</strong>: Can reject inappropriate commands<br><strong>Copy Command</strong>: Copy command to clipboard<br><strong>Direct Execution</strong>: Directly execute commands in Command mode</p></blockquote><h4 id="option-handling" tabindex="-1">Option Handling <a class="header-anchor" href="#option-handling" aria-label="Permalink to &quot;Option Handling&quot;">​</a></h4><blockquote><p><strong>Single Selection</strong>: AI-provided option selection<br><strong>Custom Input</strong>: Supports custom option input<br><strong>Batch Operations</strong>: Supports batch selection and processing</p></blockquote><h4 id="feedback-system" tabindex="-1">Feedback System <a class="header-anchor" href="#feedback-system" aria-label="Permalink to &quot;Feedback System&quot;">​</a></h4><blockquote><p><strong>Like/Dislike</strong>: Provide feedback on AI responses<br><strong>Task Completion</strong>: Mark task completion status<br><strong>Retry Mechanism</strong>: Supports retry after failure</p></blockquote><h3 id="_6-layout-switching" tabindex="-1">6. Layout Switching <a class="header-anchor" href="#_6-layout-switching" aria-label="Permalink to &quot;6. Layout Switching&quot;">​</a></h3><p>Chaterm supports two interface layout modes that you can flexibly switch between based on your workflow needs:</p><h4 id="terminal-layout" tabindex="-1">Terminal Layout <a class="header-anchor" href="#terminal-layout" aria-label="Permalink to &quot;Terminal Layout&quot;">​</a></h4><blockquote><p><strong>Features</strong>: Traditional terminal-first layout<br><strong>Best For</strong>: Terminal-centric workflows with AI as an assistant<br><strong>Interface</strong>: Terminal window occupies the main area, with the AI sidebar as an auxiliary panel</p></blockquote><h4 id="agents-layout" tabindex="-1">Agents Layout <a class="header-anchor" href="#agents-layout" aria-label="Permalink to &quot;Agents Layout&quot;">​</a></h4><blockquote><p><strong>Features</strong>: AI Agent-first layout<br><strong>Best For</strong>: AI collaboration as the primary workflow, with the terminal as the execution tool<br><strong>Interface</strong>: AI conversation area occupies the main area, with the terminal window as the execution panel</p></blockquote><h4 id="how-to-switch" tabindex="-1">How to Switch <a class="header-anchor" href="#how-to-switch" aria-label="Permalink to &quot;How to Switch&quot;">​</a></h4><blockquote><p><strong>Keyboard Shortcut</strong>: Use <code>Command + E</code> (macOS) or <code>Ctrl + E</code> (Windows/Linux) to quickly switch layouts<br><strong>Settings Switch</strong>: Choose the layout mode in <a href="/docs/settings/general/">General Settings</a><br><strong>Instant Effect</strong>: Layout changes take effect immediately without restarting the application</p></blockquote><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><h3 id="basic-operations" tabindex="-1">Basic Operations <a class="header-anchor" href="#basic-operations" aria-label="Permalink to &quot;Basic Operations&quot;">​</a></h3><ol><li><strong>Open the App</strong>: Launch the Chaterm application</li><li><strong>Open the Sidebar</strong>: Click the AI icon on the right to open the sidebar</li><li><strong>Choose Mode</strong>: Select a dialog mode (Chat/Command/Agent)</li><li><strong>Select Model</strong>: Choose a model from the list (e.g., DeepSeek, Qwen)</li><li><strong>Select Host</strong>: In Agent mode, type <code>@</code> in the input box and select a target host from the dropdown list</li><li><strong>Enter Content</strong>: Type your question or command in the input box</li><li><strong>Send Message</strong>: Press Enter or click the send button</li></ol><h2 id="configuration-options" tabindex="-1">Configuration Options <a class="header-anchor" href="#configuration-options" aria-label="Permalink to &quot;Configuration Options&quot;">​</a></h2><h3 id="feature-toggles" tabindex="-1">Feature Toggles <a class="header-anchor" href="#feature-toggles" aria-label="Permalink to &quot;Feature Toggles&quot;">​</a></h3><blockquote><p><strong>Auto Execution</strong>: Configure the auto-execution strategy for commands</p></blockquote><p>For detailed configuration, please refer to <a href="/docs/ai/preferences/">AI Preferences</a>.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="common-issues" tabindex="-1">Common Issues <a class="header-anchor" href="#common-issues" aria-label="Permalink to &quot;Common Issues&quot;">​</a></h3><h4 id="_1-conversation-stuck-in-processing-state-for-a-long-time" tabindex="-1">1. Conversation stuck in processing state for a long time <a class="header-anchor" href="#_1-conversation-stuck-in-processing-state-for-a-long-time" aria-label="Permalink to &quot;1. Conversation stuck in processing state for a long time&quot;">​</a></h4><blockquote><p><strong>Session Connection</strong>: Click &quot;New Conversation&quot; to start a new session</p></blockquote><h4 id="_2-command-execution-failed" tabindex="-1">2. Command execution failed <a class="header-anchor" href="#_2-command-execution-failed" aria-label="Permalink to &quot;2. Command execution failed&quot;">​</a></h4><blockquote><p><strong>Permission Check</strong>: Ensure you have permission to execute commands<br><strong>Host Connection</strong>: Check the connection status of the target host<br><strong>Command Syntax</strong>: Verify that the command syntax is correct</p></blockquote>',55)]))}const p=o(s,[["render",i]]);export{m as __pageData,p as default};
